prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?originalId ?created WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "2dafb1f0acb24b27ae8f0dc47d14fcaa" ;
       tai:belongsTo ?corpus .

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:originalId ?originalId ;
         tai:modelCreated ?created .

  FILTER(
    CONTAINS(LCASE(STR(?modelName)), "universit") ||
    CONTAINS(LCASE(STR(?modelName)), "college") ||
    CONTAINS(LCASE(STR(?modelName)), "admission") ||
    CONTAINS(LCASE(STR(?modelName)), "apply") ||
    CONTAINS(LCASE(STR(?modelName)), "application") ||
    CONTAINS(LCASE(STR(?modelName)), "enroll") ||
    CONTAINS(LCASE(STR(?modelName)), "enrollment")
  )
}
ORDER BY DESC(?created)
LIMIT 25

